<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Text Input Form</title>
</head>
<body>

    <h1>Enter Your Text</h1>

    <!-- The form that contains the text input and the save button -->
    <form id="textForm">
        <label for="textInput">Your Text:</label>
        <br>
        <input type="text" id="textInput" name="textInput" size="50">
        <br><br>
        <button type="submit">Save Text</button>
    </form>

    <h2>Saved Text:</h2>
    <p id="savedTextDisplay">No text saved yet.</p>

    <script>
        // Get references to the HTML elements we need to work with
        const textForm = document.getElementById('textForm');
        const textInput = document.getElementById('textInput');
        const savedTextDisplay = document.getElementById('savedTextDisplay');

        // This function runs when the form is submitted
        function handleFormSubmit(event) {
            // Prevent the form from reloading the page (its default behavior)
            event.preventDefault();

            // Get the text from the input field
            const userText = textInput.value;

            // Save the text to the browser's local storage
            // This data will persist even if the user closes the browser tab
            localStorage.setItem('savedUserText', userText);

            // Display a confirmation message
            alert('Text saved successfully!');

            // Update the display area to show the newly saved text
            displaySavedText();
        }

        // This function retrieves and displays the text from local storage
        function displaySavedText() {
            const savedText = localStorage.getItem('savedUserText');
            if (savedText) {
                savedTextDisplay.textContent = savedText;
            }
        }

        // Add an event listener to the form to call our function on submission
        textForm.addEventListener('submit', handleFormSubmit);

        // When the page first loads, check if there is any saved text and display it
        document.addEventListener('DOMContentLoaded', displaySavedText);
    </script>

</body>
</html>
